for file in html_files:
    if file == 'index.html':
        continue # handled manually
        
    if file.startswith('android/') or file.startswith('ios/'):
        continue

    with open(file, 'r', encoding='utf-8') as f:
        content = f.read()
        
    old_target = '<p class="text-xs text-gray-300 font-medium">&copy; 2026 Sorula — A&Y Creations</p>'
    if old_target in content and 'tiktok.com/@sorulatest' not in content:
        content = content.replace(old_target, social_html)
        
        with open(file, 'w', encoding='utf-8') as f:
            f.write(content)
        print(f"Updated {file}")
